// Initialize or resume durable state
const input = $input.first().json || {};
const userInput = input.message || input.userInput || input.query || 'Default research request';
if (!userInput || userInput.trim().length < 10) {
  throw new Error('User input must be at least 10 characters');
}

const maxRounds = Number(input.maxRounds || 4);
const consensusThreshold = Number(input.consensusThreshold || 85);

const globalStore = this.getWorkflowStaticData('global');
if (!globalStore.agentFailures) globalStore.agentFailures = {};

const state = {
  workflowId: globalStore.workflowId || `wf_${Date.now()}_${Math.random().toString(36).slice(2, 9)}`,
  phase: input.phase || 'research',
  round: Number(input.round || 1),
  maxRounds,
  consensusThreshold,
  priority: input.priority || 'normal',
  documents: input.documents || { research: null, analysis: null, plan: null },
  refinementHistory: input.refinementHistory || [],
  consensusScores: input.consensusScores || [],
  userInput,
  agentPerformance: input.agentPerformance || { active: ['qwen','mistral','deepseek','nemotron','llama','kimi'], failed: [], timeout: [], scores: {} },
  createdAt: globalStore.createdAt || new Date().toISOString(),
  updatedAt: new Date().toISOString()
};

globalStore.workflowId = state.workflowId;
if (!globalStore.createdAt) globalStore.createdAt = state.createdAt;

return state;

// Dynamic prompt with context and round-aware refinement
const { phase, round, userInput, documents, refinementHistory, consensusScores, consensusThreshold } = $input.first().json;
const templates = {
  research: { sys: 'You are a research specialist.', obj: 'Conduct thorough, source-backed research.', fmt: 'JSON: {summary, key_findings, sources, methodology, confidence_score}' },
  analysis: { sys: 'You are a strategic analyst.', obj: 'Analyze research for risks/opportunities.', fmt: 'JSON: {analysis, risks, opportunities, strategic_implications, confidence_score}' },
  plan: { sys: 'You are a strategist.', obj: 'Create an actionable plan.', fmt: 'JSON: {strategy, action_items, timeline, resources, success_metrics, confidence_score}' }
};
const t = templates[phase];
let p = `${t.sys}
Phase: ${phase.toUpperCase()} - Round ${round}
Objective: ${t.obj}

User Request: ${userInput}

`;
if (phase === 'analysis' && documents.research) p += `Research Context
${JSON.stringify(documents.research, null, 2)}

`;
if (phase === 'plan') {
  if (documents.research) p += `Research Context
${JSON.stringify(documents.research, null, 2)}

`;
  if (documents.analysis) p += `Analysis Context
${JSON.stringify(documents.analysis, null, 2)}

`;
}
if (round > 1 && refinementHistory.length) {
  const last = refinementHistory[refinementHistory.length-1];
  if (last && Array.isArray(last.recommendations)) {
    p += `Address Prior Feedback:
${last.recommendations.map((r,i)=>`${i+1}. ${r}`).join('
')}

`;
  }
}
if (consensusScores.length) {
  const avg = consensusScores.reduce((s,x)=>s+x.score,0)/consensusScores.length;
  p += `Last Consensus: ${avg.toFixed(1)}% | Target: ${consensusThreshold}%

`;
}
p += `Instructions:
1) ${t.obj}
2) Use output format: ${t.fmt}
3) Provide actionable, well-reasoned content with citations if applicable
4) Return VALID JSON ONLY
`;
return { prompt: p, phase, round, consensusThreshold, maxRounds: $items(0,0).json.maxRounds };

// Prepare vendor-native agent calls as separate items
const { prompt, phase, round } = $input.first().json;
const active = $items(0,0).json.agentPerformance?.active || ['qwen','mistral','deepseek','nemotron','llama','kimi'];
const failures = this.getWorkflowStaticData('global').agentFailures || {};

const vendors = [
  { id:'qwen',    url:'https://dashscope.aliyuncs.com/compatible-mode/v1/chat/completions', model:'qwen2.5-72b-instruct', temp:0.7, timeout:45000 },
  { id:'mistral', url:'https://api.mistral.ai/v1/chat/completions',                            model:'mistral-small-latest',      temp:0.6, timeout:30000 },
  { id:'deepseek',url:'https://api.deepseek.com/chat/completions',                               model:'deepseek-reasoner',         temp:0.4, timeout:45000 },
  { id:'nemotron',url:'https://integrate.api.nvidia.com/v1/chat/completions',                   model:'nvidia/nemotron-4-340b-instruct', temp:0.6, timeout:45000 },
  { id:'llama',   url:'https://api.openai.com/v1/chat/completions',                              model:'gpt-4o-mini',               temp:0.7, timeout:30000 },
  { id:'kimi',    url:'https://api.moonshot.cn/v1/chat/completions',                             model:'moonshot-v1-8k',            temp:0.8, timeout:45000 }
];

const items = vendors
  .filter(v => active.includes(v.id))
  .map(v => {
    const failCount = failures[v.id] || 0;
    const useFallback = failCount >= 2;
    return {
      vendor: v.id,
      url: useFallback ? 'https://openrouter.ai/api/v1/chat/completions' : v.url,
      model: useFallback ? 'google/gemma-3-27b-it' : v.model,
      temperature: v.temp,
      timeout: v.timeout,
      prompt, phase, round,
      useFallback
    };
  });

return items.map(i => ({ json: i }));

// Aggregate responses, score quality, update failure counters
const globalStore = this.getWorkflowStaticData('global');
if (!globalStore.agentFailures) globalStore.agentFailures = {};

const responses = [];
const errors = [];

$input.all().forEach((item) => {
  const raw = item.json;
  const vendor = raw.vendor || 'unknown';
  const choices = raw.choices;
  const content = choices && choices[0] && choices[0].message && choices[0].message.content;
  if (content) {
    let parsed;
    try { parsed = JSON.parse(content); } catch(e) { parsed = { raw_content: content, confidence_score: 50 }; }
    const score = scoreQuality(parsed, $items(0,0).json.phase);
    responses.push({ vendor, content: parsed, score, fallback: !!raw.useFallback });
    globalStore.agentFailures[vendor] = 0;
  } else {
    errors.push({ vendor, error: raw.error || raw });
    globalStore.agentFailures[vendor] = (globalStore.agentFailures[vendor] || 0) + 1;
  }
});

responses.sort((a,b)=>b.score-a.score);

function scoreQuality(doc, phase){
  let s=0;
  if (doc && typeof doc==='object') s+=20;
  if (typeof doc.confidence_score==='number') s+=Math.min(doc.confidence_score*0.5,40);
  if (doc.summary||doc.analysis||doc.strategy) s+=20;
  if (phase==='research' && doc.sources && doc.key_findings) s+=20;
  if (phase==='analysis' && doc.risks && doc.opportunities) s+=20;
  if (phase==='plan' && doc.action_items && doc.timeline) s+=20;
  return Math.min(100,s);
}

return { responses, errors, phase: $items(0,0).json.phase, round: $items(0,0).json.round };

// Build committee evaluation prompt + carry context
const { responses, phase, round } = $input.first().json;
const ctx = $items(0,0).json; // from init state upstream via separate input later if needed
const prompt = `Committee Evaluation - ${phase.toUpperCase()}
Round: ${round}
Total Responses: ${responses.length}

` + responses.map((r,i)=>`#${i+1} Vendor:${r.vendor} Score:${r.score}%
${JSON.stringify(r.content, null, 2)}`).join('

') + `

Return STRICT JSON: {\

// Parse primary, fallback to backup; pass through context
const primary = $items(0,0).json;
const backup = $items(1,0).json;
const ctx = $items(2,0).json; // from Committee Prep
function parseEval(resp){
  if (!resp || !resp.choices || !resp.choices[0]) return null;
  const text = resp.choices[0].message?.content || '';
  try { return JSON.parse(text); } catch(e) { return null; }
}

let result = parseEval(primary) || parseEval(backup) || { consensus_score: 0, divergence_points: [], recommendations: [], readiness_assessment: 'incomplete' };
return { eval: result, ctx };

// Decide next step based on consensus and rounds
const { eval: evalRes, ctx } = $input.first().json;
const score = Number(evalRes.consensus_score || 0);
const threshold = Number(ctx.consensusThreshold || 85);
const canRetry = ctx.round < (ctx.maxRounds || 4);
const hasConsensus = score >= threshold;
return { hasConsensus, canRetry, score, threshold, evalRes, ctx };

// Synthesize doc using top responses
const dec = $items(0,0).json;
const top = $items(1,0).json.topK || [];
const phase = dec.ctx.phase;
let prompt = `Synthesize ${phase.toUpperCase()} Document
Use best responses, resolve conflicts, ensure coherence.
Return polished, publication-ready prose.`;
prompt += '

TOP RESPONSES:
' + top.map((r,i)=>`#${i+1} (${r.vendor}) Score:${r.score}%
${JSON.stringify(r.content, null, 2)}`).join('

');
return { synthPrompt: prompt, phase };

// Update state with synthesized or best-available, transition phase or loop
const state = $items(2,0).json; // from Init Durable State
const decision = $items(1,0).json; // from Consensus Decision
const synth = $items(0,0).json; // from Synthesize Document

const phase = decision.ctx.phase;
let doc = null;
if (synth && synth.choices && synth.choices[0]) {
  doc = { document: synth.choices[0].message.content, generated_at: new Date().toISOString() };
}
const next = { ...state };
if (doc) next.documents[phase] = doc;

if (decision.hasConsensus) {
  const order = ['research','analysis','plan'];
  const idx = order.indexOf(state.phase);
  if (idx >= 0 && idx < order.length-1) { next.phase = order[idx+1]; next.round = 1; next.refinementHistory = []; }
  else { next.phase = 'complete'; next.completedAt = new Date().toISOString(); }
  next.consensusScores.push({ phase, round: state.round, score: decision.score, ts: new Date().toISOString() });
} else if (decision.canRetry) {
  next.round = state.round + 1;
  next.refinementHistory.push({ phase, round: state.round, recommendations: decision.evalRes?.recommendations || [], score: decision.score, ts: new Date().toISOString() });
} else {
  const order = ['research','analysis','plan'];
  const idx = order.indexOf(state.phase);
  if (idx >= 0 && idx < order.length-1) { next.phase = order[idx+1]; next.round = 1; } else { next.phase = 'complete'; next.completedAt = new Date().toISOString(); }
  next.consensusScores.push({ phase, round: state.round, score: decision.score, ts: new Date().toISOString(), note: 'max rounds' });
}

next.updatedAt = new Date().toISOString();
return next;

// Final report summary
const s = $input.first().json;
const avg = s.consensusScores.length ? (s.consensusScores.reduce((a,b)=>a+b.score,0)/s.consensusScores.length) : 0;
return { finalReport: { executive_summary: { workflow_id: s.workflowId, completed: !!s.completedAt, completed_at: s.completedAt, average_consensus: Number(avg.toFixed(1)), total_rounds: s.consensusScores.length }, documents: s.documents, performance: { consensus: s.consensusScores, refinements: s.refinementHistory } }, timestamp: new Date().toISOString() };

